// Normalize input from AppFolio webhook, Tally, or Typeform
// Outputs a consistent shape regardless of source
try {
  const d = $input.item.json;

  // Detect source format and normalize
  let normalized;

  if (d.fields) {
    // Tally format: { fields: [{ label, value }] }
    const fieldMap = {};
    for (const f of d.fields) {
      fieldMap[f.label.toLowerCase().replace(/\s+/g, '_')] = f.value;
    }
    normalized = {
      unit: fieldMap.unit || fieldMap.unit_number || '',
      tenant_name: fieldMap.tenant_name || fieldMap.name || '',
      tenant_email: fieldMap.tenant_email || fieldMap.email || '',
      tenant_phone: fieldMap.tenant_phone || fieldMap.phone || '',
      issue_description: fieldMap.issue_description || fieldMap.description || fieldMap.issue || '',
      stated_urgency: fieldMap.urgency || 'unknown',
      source: 'tally'
    };
  } else if (d.form_response) {
    // Typeform format
    const answers = d.form_response.answers || [];
    normalized = {
      unit: answers[0] ? answers[0].text : '',
      tenant_name: answers[1] ? answers[1].text : '',
      tenant_email: answers[2] ? answers[2].email : '',
      tenant_phone: answers[3] ? answers[3].phone_number : '',
      issue_description: answers[4] ? answers[4].text : '',
      stated_urgency: answers[5] ? answers[5].choice.label : 'unknown',
      source: 'typeform'
    };
  } else {
    // AppFolio webhook or generic JSON
    normalized = {
      unit: d.unit || d.unit_number || d.property_unit || '',
      tenant_name: d.tenant_name || d.name || d.resident_name || '',
      tenant_email: d.tenant_email || d.email || d.resident_email || '',
      tenant_phone: d.tenant_phone || d.phone || '',
      issue_description: d.issue_description || d.description || d.details || d.message || '',
      stated_urgency: d.urgency || d.priority || 'unknown',
      source: d.source || 'appfolio'
    };
  }

  normalized.received_at = new Date().toISOString();
  normalized.ticket_id = 'MR-' + Date.now().toString(36).toUpperCase();

  return { json: normalized };
} catch (err) {
  return { json: { error: 'Failed to normalize input: ' + err.message } };
}

// Build the Claude prompt for maintenance triage classification
try {
  const d = $input.item.json;

  const prompt = `You are a property management maintenance triage AI. Classify this maintenance request and draft a vendor dispatch message.

Maintenance Request:
- Unit: ${d.unit}
- Tenant: ${d.tenant_name}
- Description: ${d.issue_description}
- Tenant-stated urgency: ${d.stated_urgency}

Respond in EXACTLY this JSON format (no markdown, no code fences):
{
  "urgency": "emergency|urgent|routine",
  "category": "plumbing|electrical|hvac|structural|cosmetic",
  "reasoning": "Brief explanation of classification",
  "vendor_dispatch_message": "Professional message to send to the assigned vendor including unit number, issue summary, and urgency level",
  "tenant_confirmation_message": "Friendly message to send to the tenant confirming receipt and expected timeline",
  "sla_hours": 2|24|72
}

Classification rules:
- EMERGENCY: Active flooding, gas leak, fire damage, no heat in winter, sewage backup, electrical hazard. SLA: 2 hours.
- URGENT: No hot water, broken lock, major appliance failure, HVAC failure in extreme weather. SLA: 24 hours.
- ROUTINE: Cosmetic damage, minor leak (contained), appliance wear, paint, fixtures. SLA: 72 hours.

Always err on the side of higher urgency when in doubt.`;

  const requestBody = {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1024,
    messages: [
      { role: 'user', content: prompt }
    ]
  };

  return {
    json: {
      ...d,
      ai_request_body: requestBody
    }
  };
} catch (err) {
  return { json: { ...$input.item.json, error: 'Failed to build AI prompt: ' + err.message } };
}

// Parse Claude's response and merge with original request data
try {
  const upstream = $('Build AI Prompt').item.json;
  const aiResponse = $input.item.json;

  let responseText = '';
  if (aiResponse.content && aiResponse.content.length > 0) {
    responseText = aiResponse.content[0].text;
  }

  // Strip markdown code fences if present
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch (parseErr) {
    parsed = {
      urgency: 'urgent',
      category: 'plumbing',
      reasoning: 'AI response could not be parsed — defaulting to urgent/plumbing for safety',
      vendor_dispatch_message: 'Maintenance request received for unit ' + upstream.unit + '. Please respond ASAP.',
      tenant_confirmation_message: 'We have received your maintenance request and a technician will be in touch shortly.',
      sla_hours: 24
    };
  }

  return {
    json: {
      ticket_id: upstream.ticket_id,
      unit: upstream.unit,
      tenant_name: upstream.tenant_name,
      tenant_email: upstream.tenant_email,
      tenant_phone: upstream.tenant_phone,
      issue_description: upstream.issue_description,
      stated_urgency: upstream.stated_urgency,
      received_at: upstream.received_at,
      source: upstream.source,
      ai_urgency: parsed.urgency,
      ai_category: parsed.category,
      ai_reasoning: parsed.reasoning,
      vendor_dispatch_message: parsed.vendor_dispatch_message,
      tenant_confirmation_message: parsed.tenant_confirmation_message,
      sla_hours: parsed.sla_hours
    }
  };
} catch (err) {
  const upstream = $('Build AI Prompt').item.json;
  return {
    json: {
      ...upstream,
      ai_urgency: 'urgent',
      ai_category: 'plumbing',
      ai_reasoning: 'Error parsing AI response: ' + err.message,
      vendor_dispatch_message: 'Maintenance request for unit ' + (upstream.unit || 'unknown') + '. Please respond.',
      tenant_confirmation_message: 'Your request has been received. We will be in touch shortly.',
      sla_hours: 24
    }
  };
}

// Merge AI triage data with vendor lookup result
// This is the canonical data node — all downstream nodes reference this
try {
  const triage = $('Parse AI Response').item.json;
  const vendor = $input.item.json;

  // SLA window config (parameterized — swap per prospect)
  const slaWindows = {
    emergency: '{{EMERGENCY_SLA_HOURS}} hours',
    urgent: '{{URGENT_SLA_HOURS}} hours',
    routine: '{{ROUTINE_SLA_HOURS}} hours'
  };

  const slaWindow = slaWindows[triage.ai_urgency] || '24 hours';

  // Build vendor email body
  const vendorEmailSubject = '[' + triage.ai_urgency.toUpperCase() + '] Maintenance Request — Unit ' + triage.unit + ' — ' + triage.ai_category;
  const vendorEmailBody = 'Hello ' + (vendor['Vendor Name'] || 'Vendor') + ',\n\n' +
    triage.vendor_dispatch_message + '\n\n' +
    'Ticket ID: ' + triage.ticket_id + '\n' +
    'Unit: ' + triage.unit + '\n' +
    'Category: ' + triage.ai_category + '\n' +
    'Urgency: ' + triage.ai_urgency.toUpperCase() + '\n' +
    'SLA: Respond within ' + slaWindow + '\n\n' +
    'Please confirm receipt and estimated arrival time.\n\n' +
    'Thank you,\n{{COMPANY_NAME}} Maintenance Team';

  // Build tenant confirmation email
  const tenantEmailSubject = 'Maintenance Request Received — ' + triage.ticket_id;
  const tenantEmailBody = 'Dear ' + triage.tenant_name + ',\n\n' +
    triage.tenant_confirmation_message + '\n\n' +
    'Ticket ID: ' + triage.ticket_id + '\n' +
    'Category: ' + triage.ai_category.charAt(0).toUpperCase() + triage.ai_category.slice(1) + '\n' +
    'Expected response: Within ' + slaWindow + '\n\n' +
    'If this is an emergency and you have not been contacted within 2 hours, please call our office directly at {{PM_OFFICE_PHONE}}.\n\n' +
    'Best regards,\n{{COMPANY_NAME}} Management';

  // Sheets log row
  const sheetsRow = {
    'Ticket ID': triage.ticket_id,
    'Date': triage.received_at,
    'Unit': triage.unit,
    'Tenant': triage.tenant_name,
    'Description': triage.issue_description,
    'Category': triage.ai_category,
    'Urgency': triage.ai_urgency,
    'Vendor': vendor['Vendor Name'] || 'Unassigned',
    'Vendor Email': vendor['Email'] || '{{FALLBACK_VENDOR_EMAIL}}',
    'SLA Window': slaWindow,
    'Status': 'Dispatched',
    'Tenant Notified': 'Yes'
  };

  return {
    json: {
      ...triage,
      vendor_name: vendor['Vendor Name'] || 'Unassigned',
      vendor_email: vendor['Email'] || '{{FALLBACK_VENDOR_EMAIL}}',
      vendor_phone: vendor['Phone'] || '',
      sla_window: slaWindow,
      vendor_email_subject: vendorEmailSubject,
      vendor_email_body: vendorEmailBody,
      tenant_email_subject: tenantEmailSubject,
      tenant_email_body: tenantEmailBody,
      sheets_row: sheetsRow
    }
  };
} catch (err) {
  return { json: { ...$('Parse AI Response').item.json, error: 'Prep dispatch failed: ' + err.message } };
}

// Build flat object matching Sheets header row exactly
// Lesson 36: always use a Prep node before Sheets to avoid defineBelow issues
try {
  const d = $('Prep Dispatch Data').item.json;
  return {
    json: {
      'Ticket ID': d.ticket_id,
      'Date': d.received_at,
      'Unit': d.unit,
      'Tenant': d.tenant_name,
      'Description': d.issue_description,
      'Category': d.ai_category,
      'Urgency': d.ai_urgency,
      'Vendor': d.vendor_name,
      'Vendor Email': d.vendor_email,
      'SLA Window': d.sla_window,
      'Status': 'Dispatched',
      'Tenant Notified': 'Yes'
    }
  };
} catch (err) {
  return { json: { 'Ticket ID': 'ERROR', 'Date': new Date().toISOString(), 'Description': err.message } };
}

// Build the webhook response payload and log success
try {
  const d = $('Prep Dispatch Data').item.json;
  return {
    json: {
      status: 'success',
      ticket_id: d.ticket_id,
      classification: {
        urgency: d.ai_urgency,
        category: d.ai_category,
        reasoning: d.ai_reasoning
      },
      vendor_assigned: {
        name: d.vendor_name,
        email: d.vendor_email
      },
      sla_window: d.sla_window,
      tenant_notified: true,
      emergency_alert_sent: d.ai_urgency === 'emergency',
      message: 'Maintenance request ' + d.ticket_id + ' triaged and dispatched successfully.'
    }
  };
} catch (err) {
  return {
    json: {
      status: 'error',
      message: 'Workflow completed with errors: ' + err.message
    }
  };
}

// Error handler — logs error details for debugging
try {
  const error = $input.item.json;
  return {
    json: {
      status: 'workflow_error',
      error_message: error.message || 'Unknown error',
      error_node: error.node || 'Unknown node',
      timestamp: new Date().toISOString(),
      workflow: 'PM Maintenance Triage'
    }
  };
} catch (err) {
  return {
    json: {
      status: 'error_handler_failed',
      message: err.message,
      timestamp: new Date().toISOString()
    }
  };
}
